const raw = $json.query || '';
let parsed = {};
try {
  let toParse = raw;
  if (typeof toParse === 'string') {
    const start = toParse.indexOf('{');
    const end = toParse.lastIndexOf('}');
    if (start !== -1 && end > start) {
      toParse = toParse.substring(start, end + 1);
    }
    parsed = JSON.parse(toParse);
  } else {
    parsed = toParse;
  }
} catch(e) {
  parsed = { agent: 'unknown', task: raw, context: '' };
}
return [{
  json: {
    agent: parsed.agent || 'unknown',
    task: parsed.task || '',
    context: parsed.context || ''
  }
}];

const input = $('Parse Input').first().json;
const persona = $('Load Persona').first()?.json;

const agentId = input.agent || 'unknown';
const task = input.task || '';
const context = input.context || '';

// Fallback if persona not found
if (!persona || !persona.content) {
  return [{
    json: {
      systemPrompt: `You are a helpful expert. Complete the following task thoroughly and return a structured result. Respond in the same language as the task.`,
      userMessage: task
    }
  }];
}

const systemPrompt = `# EXPERT AGENT: ${agentId}

${persona.content}

# INSTRUCTIONS
You have been activated as an expert agent for a specific task.
Complete the task thoroughly and return a structured result.
Respond in the same language as the task.
Use available tools (HTTP Request, Web Search, MCP Client) when they help accomplish the task.

${context ? '# CONVERSATION CONTEXT\n' + context : ''}`;

return [{
  json: {
    systemPrompt,
    userMessage: task
  }
}];

const qType = typeof query;
let url = '', method = 'GET', headers = {}, body = null;

if (qType === 'object' && query !== null) {
  url = query.url || '';
  method = (query.method || 'GET').toUpperCase();
  headers = query.headers || {};
  body = query.body || null;
} else if (qType === 'string') {
  try {
    const parsed = JSON.parse(query);
    url = parsed.url || '';
    method = (parsed.method || 'GET').toUpperCase();
    headers = parsed.headers || {};
    body = parsed.body || null;
  } catch(e) {
    url = query;
  }
}

if (!url) return 'Error: no URL provided';

try {
  const opts = { method, url, headers };
  if (body && method !== 'GET') {
    opts.body = typeof body === 'string' ? body : JSON.stringify(body);
    if (!headers['Content-Type']) headers['Content-Type'] = 'application/json';
  }
  const resp = await helpers.httpRequest(opts);
  const result = typeof resp === 'string' ? resp : JSON.stringify(resp);
  return result.length > 10000 ? result.substring(0, 10000) + '... (truncated)' : result;
} catch(e) {
  return 'HTTP Error: ' + e.message;
}

let input;
try { input = JSON.parse(query); } catch(e) { input = { q: query }; }
const q = input.q || input.query || query;
const result = await helpers.httpRequest({
  method: 'GET',
  url: `http://searxng:8080/search?q=${encodeURIComponent(q)}&format=json&language=de`,
  headers: { 'Accept': 'application/json' }
});
const hits = (result.results || []).slice(0, 5).map(r =>
  `${r.title}\n${r.url}\n${r.content || ''}`
).join('\n\n');
return hits || 'Keine Ergebnisse gefunden.';

const qType = typeof query;
let mcpUrl = '', toolName = '', args = {};

if (qType === 'object' && query !== null) {
  mcpUrl = query.mcp_url || '';
  toolName = query.tool_name || '';
  args = query.arguments || {};
} else if (qType === 'string') {
  try {
    const parsed = JSON.parse(query);
    mcpUrl = parsed.mcp_url || '';
    toolName = parsed.tool_name || '';
    args = parsed.arguments || {};
  } catch(e) {
    return 'Parse error: query=' + String(query).substring(0,200) + ' type=' + qType;
  }
} else {
  return 'Unexpected query type: ' + qType + ' value: ' + String(query).substring(0,200);
}

if (typeof args === 'string') try { args = JSON.parse(args); } catch(e) {}
if (!mcpUrl || !toolName) return 'Fehler: mcp_url=' + mcpUrl + ' tool_name=' + toolName;

function parseSSE(raw) {
  const str = String(raw);
  let lines = str.split('\n');
  if (lines.length <= 1) lines = str.split('\\n');
  for (let i = lines.length - 1; i >= 0; i--) {
    if (lines[i].startsWith('data: ')) {
      return JSON.parse(lines[i].substring(6));
    }
  }
  return null;
}

try {
  const hdrs = {'Content-Type':'application/json','Accept':'application/json, text/event-stream'};

  const init = await helpers.httpRequest({
    method: 'POST', url: mcpUrl,
    headers: hdrs,
    body: JSON.stringify({jsonrpc:'2.0',id:1,method:'initialize',params:{protocolVersion:'2024-11-05',capabilities:{},clientInfo:{name:'n8n-claw-sub-agent',version:'1.0'}}}),
    returnFullResponse: true, encoding: 'utf-8', json: false
  });
  const sid = init.headers && init.headers['mcp-session-id'];
  if (!sid) return 'MCP: Kein session-id. Body: ' + String(init.body||init).substring(0,200);

  hdrs['mcp-session-id'] = sid;

  await helpers.httpRequest({
    method: 'POST', url: mcpUrl,
    headers: hdrs,
    body: JSON.stringify({jsonrpc:'2.0',method:'notifications/initialized'}),
    json: false
  });

  const listResp = await helpers.httpRequest({
    method: 'POST', url: mcpUrl,
    headers: hdrs,
    body: JSON.stringify({jsonrpc:'2.0',id:2,method:'tools/list',params:{}}),
    json: false
  });
  const listResult = parseSSE(listResp);
  if (listResult && listResult.result && listResult.result.tools) {
    const tool = listResult.result.tools.find(t => t.name === toolName);
    if (tool && tool.inputSchema && tool.inputSchema.required) {
      for (const req of tool.inputSchema.required) {
        if (args[req] === undefined || args[req] === null) {
          args[req] = '';
        }
      }
    }
  }

  const resp = await helpers.httpRequest({
    method: 'POST', url: mcpUrl,
    headers: hdrs,
    body: JSON.stringify({jsonrpc:'2.0',id:3,method:'tools/call',params:{name:toolName,arguments:args}}),
    returnFullResponse: true, encoding: 'utf-8', json: false
  });

  const result = parseSSE(resp.body || resp);
  if (!result) return 'MCP: Keine Daten. Response: ' + String(resp.body || resp).substring(0,500);
  if (result.error) return 'MCP Error: ' + JSON.stringify(result.error);
  return result.result?.content?.[0]?.text || JSON.stringify(result.result);
} catch(e) {
  return 'MCP Error: ' + e.message;
}

let input;
try { input = JSON.parse(query); } catch(e) { input = { url: query }; }
if (!input.url) return 'Error: url is required';
try {
  const resp = await helpers.httpRequest({
    method: 'POST',
    url: 'http://crawl4ai:11235/crawl',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ urls: [input.url], crawler_config: { type: 'CrawlerRunConfig', params: { stream: false, cache_mode: 'bypass' } } }),
    timeout: 30000
  });
  const results = resp.results || resp;
  const result = Array.isArray(results) ? results[0] : results;
  if (!result.success) return 'Error: ' + (result.error_message || 'Crawl failed');
  const mdObj = result.markdown || {};
  const md = typeof mdObj === 'string' ? mdObj : (mdObj.raw_markdown || '');
  return md.substring(0, 8000);
} catch(e) {
  return 'Error fetching page: ' + e.message;
}

const agentOutput = $('Sub-Agent').first().json.output || 'No result from expert agent.';
const agentId = $('Parse Input').first().json.agent || 'unknown';

return [{
  json: {
    result: agentOutput,
    expert: agentId
  }
}];
